// Validate input fields from form submission
const body = $input.first().json.body || {};
const errors = [];

// Required fields
if (!body.session_uuid) errors.push('session_uuid required');
if (!body.name || body.name.trim().length < 2) errors.push('name required (min 2 chars)');
if (!body.email || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(body.email)) errors.push('valid email required');
if (!body.message || body.message.trim().length < 10) errors.push('message required (min 10 chars)');

// UUID v4 format
const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;
if (body.session_uuid && !uuidRegex.test(body.session_uuid)) {
  errors.push('session_uuid must be valid v4 UUID');
}

// GDPR consent
if (body.consent_given !== true) {
  errors.push('consent_given must be true');
}

if (errors.length > 0) {
  return [{
    json: {
      validation_failed: true,
      error_code: body.consent_given !== true ? 'MISSING_CONSENT' : 'INVALID_INPUT',
      message: errors.join('; ')
    }
  }];
}

// Pass through validated data
return [{
  json: {
    validation_failed: false,
    session_uuid: body.session_uuid,
    name: body.name.trim(),
    email: body.email.trim().toLowerCase(),
    company: (body.company || '').trim(),
    website: (body.website || '').trim(),
    phone: (body.phone || '').trim(),
    message: body.message.trim(),
    consent_given: true
  }
}];

// Regelbaserad lead scoring — transparent och debuggbar
// OBS: Supabase REST med Prefer: return=representation returnerar
// varje rad som separat n8n-item. Använd .all().map() för att samla.
const prospects = $input.all().map(item => item.json);
const prospect = Array.isArray(prospects[0]) ? prospects[0][0] : prospects[0];
const original = $('Validate Input').first().json;

let score = 0;

// Company present
if (original.company && original.company.length > 1) score += 10;

// Website present
if (original.website && original.website.length > 4) score += 10;

// Phone present
if (original.phone && original.phone.length > 5) score += 5;

// Message length signals seriousness
const wordCount = original.message.split(/\s+/).length;
if (wordCount >= 30) score += 15;
else if (wordCount >= 15) score += 10;
else if (wordCount >= 10) score += 5;

// Service mentions in message (case-insensitive)
const msg = original.message.toLowerCase();
const serviceKeywords = ['crm', 'automation', 'voice', 'agent', 'chatbot', 'hemsida', 'integration', 'n8n', 'supabase'];
const matches = serviceKeywords.filter(k => msg.includes(k));
score += matches.length * 5;

// Cap at 100
score = Math.min(score, 100);

return [{
  json: {
    lead_id: prospect.id,
    session_uuid: prospect.session_uuid,
    name: prospect.name,
    email: prospect.email,
    company: prospect.company,
    message: prospect.message,
    score: score
  }
}];

// Format final response to webhook caller
const aiResponseRaw = $('Generate AI Response').first().json;
const ragResult = $('Query Knowledge Base').first().json;
const lead = $('Calculate Lead Score').first().json;

// OpenAI returnerar choices[0].message.content
const aiText = aiResponseRaw.choices?.[0]?.message?.content || 'Tack för ditt meddelande, ' + lead.name + '. Joakim återkommer personligen inom 24 timmar med ett konkret förslag baserat på det du beskrivit.';

return [{
  json: {
    status: 'success',
    lead_id: lead.lead_id,
    ai_response: aiText,
    best_match_similarity: ragResult.best_similarity || 0
  }
}];

// Build OpenAI payload — separat nod för läsbar systemprompt
// Bevarar svenska tecken och radbrytningar utan escape-helvete

const leadData = $('Calculate Lead Score').first().json;
const ragData = $('Query Knowledge Base').first().json;

const systemPrompt = `**KRITISK FÖRSTA REGEL — språk:**
Du MÅSTE svara på det språk som anges i fältet "Svarsspråk". Om Svarsspråk är ENGLISH, svara på engelska. Om SWEDISH, svara på svenska. Inga undantag.

---

Du är en pragmatisk AI-arkitekt som snabbt och konkret analyserar ett inkommande lead och föreslår lösningar. Din ton är direkt, professionell och helt utan marketing-fluff.

## 1. Lyssna på det EXAKTA problemet
Läs noga VAD kunden vill ha hjälp med.
- Om kunden vill ha "fler kunder", prata om lead generation, konvertering och uppföljning.
- Om kunden pratar om "tidsbrist" eller "missade samtal", prata om automatiska bokningssystem och kundtjänst.
Ditt svar MÅSTE matcha kundens specifika behov. Prata aldrig om admin/bokningssystem om kunden explicit ber om mer försäljning.

## 2. Format: Två lösningar
Ditt svar ska alltid innehålla exakt 2 olika AI-lösningar/angreppssätt på kundens specifika problem.
- Extremt kortfattat: Max 3-4 meningar totalt.
- Skriv i löptext (inga punktlistor, inga rubriker).
- Inga hälsningsfraser ("Hej och tack"). Gå rakt på sak.

## 3. Hur du avslutar (VIKTIGT)
- Du får INTE skriva att "vi kommer höra av oss", "jag ringer dig" eller liknande. (Systemet lägger automatiskt till detta efter din text).
- Du får INTE ställa några frågor ("Hur låter det?", "Vad tar mest tid?").
- Avsluta bara texten direkt efter att du presenterat den andra lösningen.

## 4. Komplett exempel (Följ denna längd och struktur exakt!)

INKOMMANDE MEDDELANDE:
"Hej, jag driver en massageklinik och behöver fler kunder."

DITT SVAR:
"Att hitta nya kunder tar tid som du hellre lägger på behandlingar. Vi kan lösa detta på två sätt: antingen sätter vi upp en AI-agent som dygnet runt fångar upp och konverterar hemsidebesökare till bokade tider, eller så automatiserar vi en proaktiv uppföljning via SMS med dina tidigare kunder för att snabbt fylla luckor i din kalender."

## Absolut förbjudet
- Att skriva att du ska höra av dig eller ta kontakt.
- Att ställa frågor (kunden kan inte svara i detta gränssnitt).
- Säljiga fraser som "Föreställ dig..." eller "Skräddarsydda lösningar".
- Att svara på ett annat problem än det kunden faktiskt tog upp!`;

// Språkdetektering
const isEnglish = /\b(the|and|is|are|we|our|can|you|help|with|have|this|that|from)\b/i.test(leadData.message) && !/[åäöÅÄÖ]/.test(leadData.message);
const svarssprak = isEnglish ? 'ENGLISH' : 'SWEDISH';
const userMessage = `Svarsspråk: ${svarssprak}

Besökarens meddelande:
"${leadData.message}"

Namn: ${leadData.name}
Företag: ${leadData.company || 'Ej angivet'}

Kunskapsbas-träffar:
${JSON.stringify(ragData.matches || [])}

Generera de 2 lösningarna i löptext enligt instruktionerna. Max 4 meningar.`;

const payload = {
  model: 'gpt-4o-mini',
  max_tokens: 300,
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userMessage }
  ]
};

return [{
  json: {
    payload: payload,
    // Behåll lead-data för senare noder
    lead_id: leadData.lead_id,
    session_uuid: leadData.session_uuid,
    name: leadData.name,
    email: leadData.email,
    company: leadData.company,
    message: leadData.message,
    score: leadData.score
  }
}];
